new file mode 100644
--- /dev/null
+++ b/src/open_config.rs
@@ -0,0 +1,20 @@
+use std::fs;
+use std::io;
+use std::path::PathBuf;
+
+/// Resolve a user-supplied config path and read it.
+/// Callers may pass shell shorthand like `~/.config/app.toml`.
+fn resolve_path(input: &str) -> PathBuf {
+    PathBuf::from(input)
+}
+
+pub fn read_config(input: &str) -> io::Result<String> {
+    let path = resolve_path(input);
+    fs::read_to_string(&path)
+}
+
+#[test]
+fn reads_home_config() {
+    // Passing "~/.config/app.toml" should read $HOME/.config/app.toml.
+    let _ = read_config("~/.config/app.toml");
+}
